  ('retired-10ced7e2-moex-00169', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '依據性別工作平等法之規定，為促進性別工作之平等，下列何者不屬於主管機關依法應採取之措施？', '["對於雇主設置哺集乳室，應給予經費補助", "對於雇主提供托兒措施，應給予適當之表揚", "為協助因育兒而離職之受雇者再就業，應提供就業服務或職業訓練", "對於僱用因結婚而離職之受雇者成效卓著者，得給予適當之獎勵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00170', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '下列何者非行政程序法明文之一般法律原則？', '["行政效率原則", "禁止不當聯結原則", "平等原則", "比例原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00171', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3d2b73b6', 'sub-retired-10ced7e2-03', NULL, 'single_choice', '有關不溯及既往原則之敘述，下列何者錯誤？', '["不溯及既往原則與信賴保護原則相關", "不溯及既往原則涉及立法之原則", "不溯及既往原則涉及法律之適用", "現在制定之法規適用於過去已終結之事實，並非溯及既往"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
